import{_ as a,o as r,c as i,a2 as t}from"./chunks/framework.B72_uj9U.js";const m=JSON.parse('{"title":"Chapter 14: Provider Abstraction","description":"Build a flexible provider abstraction layer that lets your coding agent work with any LLM backend through a unified interface.","frontmatter":{"title":"Chapter 14: Provider Abstraction","description":"Build a flexible provider abstraction layer that lets your coding agent work with any LLM backend through a unified interface."},"headers":[],"relativePath":"learn/linear/14-provider-abstraction/index.md","filePath":"learn/linear/14-provider-abstraction/index.md"}'),n={name:"learn/linear/14-provider-abstraction/index.md"};function o(l,e,s,d,c,p){return r(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="provider-abstraction" tabindex="-1">Provider Abstraction <a class="header-anchor" href="#provider-abstraction" aria-label="Permalink to &quot;Provider Abstraction&quot;">​</a></h1><p>A production coding agent should not be welded to a single LLM provider. Users want to choose between Anthropic, OpenAI, local models via Ollama, and whatever new provider appears next month. Your agent&#39;s core logic — the agentic loop, tool system, and conversation management — should be completely decoupled from the specifics of any one API. This chapter teaches you how to build that decoupling properly.</p><p>We start with the abstraction principles that guide good provider interfaces, then dive into Rust&#39;s trait system as the mechanism for defining provider contracts. You will implement the adapter pattern to wrap each provider&#39;s unique API behind a common interface, building concrete adapters for Anthropic, OpenAI, and Ollama. Along the way, we handle the messy realities: different providers support different model capabilities, streaming formats vary, and error shapes differ.</p><p>The chapter also covers runtime provider switching (letting users change models mid-session), fallback chains for resilience, and cost/usage tracking across providers. By the end, you will have a provider layer that makes adding a new LLM backend a matter of implementing a single trait rather than touching code throughout the agent.</p><h2 id="learning-objectives" tabindex="-1">Learning Objectives <a class="header-anchor" href="#learning-objectives" aria-label="Permalink to &quot;Learning Objectives&quot;">​</a></h2><ul><li>Apply abstraction principles to design a provider interface that captures LLM capabilities without leaking implementation details</li><li>Use Rust traits and associated types to define a provider contract with compile-time safety guarantees</li><li>Implement the adapter pattern to wrap Anthropic, OpenAI, and Ollama APIs behind a unified interface</li><li>Build a model capabilities registry that tracks what each provider/model combination supports</li><li>Implement runtime provider switching with fallback chains and automatic retry logic</li><li>Add cost and usage tracking that works transparently across all providers</li></ul><h2 id="subchapters" tabindex="-1">Subchapters <a class="header-anchor" href="#subchapters" aria-label="Permalink to &quot;Subchapters&quot;">​</a></h2><ol><li><a href="/linear/14-provider-abstraction/01-abstraction-principles.html">Abstraction Principles</a></li><li><a href="/linear/14-provider-abstraction/02-trait-based-design.html">Trait Based Design</a></li><li><a href="/linear/14-provider-abstraction/03-adapter-pattern.html">Adapter Pattern</a></li><li><a href="/linear/14-provider-abstraction/04-anthropic-provider.html">Anthropic Provider</a></li><li><a href="/linear/14-provider-abstraction/05-openai-provider.html">OpenAI Provider</a></li><li><a href="/linear/14-provider-abstraction/06-ollama-local-provider.html">Ollama Local Provider</a></li><li><a href="/linear/14-provider-abstraction/07-model-capabilities-registry.html">Model Capabilities Registry</a></li><li><a href="/linear/14-provider-abstraction/08-runtime-switching.html">Runtime Switching</a></li><li><a href="/linear/14-provider-abstraction/09-fallback-and-retry.html">Fallback and Retry</a></li><li><a href="/linear/14-provider-abstraction/10-cost-and-usage-tracking.html">Cost and Usage Tracking</a></li><li><a href="/linear/14-provider-abstraction/11-provider-testing.html">Provider Testing</a></li><li><a href="/linear/14-provider-abstraction/12-summary.html">Summary</a></li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Chapter 3 (understanding of LLM API request/response structures)</li><li>Chapter 8 (streaming patterns and server-sent events)</li></ul>',10)])])}const u=a(n,[["render",o]]);export{m as __pageData,u as default};
